import{_ as a,o as n,c as o,a3 as t}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"31. Salary Packaging","description":"","frontmatter":{"title":"31. Salary Packaging","eba":"Biomedical Engineers 2025-2028","topics":["wages","salary-packaging","preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/wages/31-salary-packaging.md","filePath":"ebas/biomedical-engineers/wages/31-salary-packaging.md"}'),s={name:"ebas/biomedical-engineers/wages/31-salary-packaging.md"};function r(i,e,l,c,p,g){return n(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="_31-salary-packaging" tabindex="-1">31. Salary Packaging <a class="header-anchor" href="#_31-salary-packaging" aria-label="Permalink to &quot;31. Salary Packaging&quot;">​</a></h1><p><strong>31.1</strong> An Employee may elect to salary package the current salary specified in <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a> in accordance with the Employer’s policy.</p><p><strong>31.2</strong> The Employee will compensate the Employer from within their salary, for any Fringe Benefits Tax (FBT) incurred as a consequence of the Employee’s salary packaging arrangement. Where the Employee chooses not to pay any of the costs associated with their salary packaging, the Employer may cease the Employee&#39;s salary packaging arrangements.</p><p><strong>31.3</strong> The Employee may elect to convert the amount packaged to salary for any reason, including where salary packaging ceases to be an advantage to the Employee because of subsequent changes to FBT legislation. Any costs associated with the conversion to salary will be borne by the Employee and the Employer will not be liable to make up any benefit lost as a consequence of an Employee&#39;s decision to convert to salary.</p><p><strong>31.4</strong> The Employee will be responsible for all costs associated with the administration of their salary packaging arrangements, provided that such costs will be confined to reasonable commercial charges as levied directly by the external salary packaging provider and/or in- house payroll service (as applicable), as varied from time to time.</p><p><strong>31.5</strong> Employees who are considering salary packaging should seek independent financial advice. The Employer will not be responsible for the cost or outcome of any such advice.</p><p><strong>31.6</strong> Superannuation contributions paid by the Employer into an approved fund will be calculated on the Employee’s pre-packaged rate of pay.</p><p>Plain language terms: salary sacrifice, novated lease.</p>',8)])])}const h=a(s,[["render",r]]);export{d as __pageData,h as default};
